import { Request, Response, NextFunction } from 'express';
import * as service from './service';
import { createTaskValidator, updateAvailabilityValidator, rerollTaskValidator } from './validator';

// Create Task
export async function createTask(req: Request, res: Response, next: NextFunction) {
  try {
    const input = createTaskValidator.parse(req.body);
    const task = await service.createTask(input, req.user.id);
    res.status(201).json(task);
  } catch (error) {
    next(error);
  }
}

// Update Task Availability
export async function updateTaskAvailability(req: Request, res: Response, next: NextFunction) {
  try {
    const input = updateAvailabilityValidator.parse({ ...req.body, id: req.params.id });
    const task = await service.updateTaskAvailability(input, req.user.id);
    res.status(200).json(task);
  } catch (error) {
    next(error);
  }
}

// Re-roll Task
export async function rerollTask(req: Request, res: Response, next: NextFunction) {
  try {
    const input = rerollTaskValidator.parse({ id: req.params.id });
    const task = await service.rerollTask(input, req.user.id);
    res.status(200).json(task);
  } catch (error) {
    next(error);
  }
}

import { TaskRepository } from './repository';
import { TaskDTO, CreateTaskDTO, UpdateAvailabilityDTO } from './dto';
import { AppError } from '../../utils/errors';
import { verifyAdminPrivileges } from '../../utils/auth';

export async function createTask(input: CreateTaskDTO, userId: string): Promise<TaskDTO> {
  await verifyAdminPrivileges(input.groupId, userId);
  const task = await TaskRepository.create(input);
  return task;
}

export async function updateTaskAvailability(input: UpdateAvailabilityDTO, userId: string): Promise<TaskDTO> {
  await verifyAdminPrivileges(input.groupId, userId);
  const task = await TaskRepository.updateAvailability(input.id, input.unavailableMembers);
  return task;
}

export async function rerollTask(input: { id: string }, userId: string): Promise<TaskDTO> {
  const task = await TaskRepository.findById(input.id);
  if (!task) {
    throw new AppError('Task not found', 404);
  }
  await verifyAdminPrivileges(task.groupId, userId);
  const updatedTask = await TaskRepository.rerollAssignees(task);
  return updatedTask;
}

import { TaskModel } from './model';
import { CreateTaskDTO } from './dto';

export class TaskRepository {
  static async create(input: CreateTaskDTO) {
    const task = new TaskModel(input);
    await task.save();
    return task.toDTO();
  }

  static async updateAvailability(id: string, unavailableMembers: string[]) {
    const task = await TaskModel.findById(id);
    if (!task) {
      throw new Error('Task not found');
    }
    task.unavailableMembers = unavailableMembers;
    await task.save();
    return task.toDTO();
  }

  static async rerollAssignees(task: any) {
    task.assignees = this.shuffleAssignees(task.assignees);
    task.rotationIndex = 0;
    await task.save();
    return task.toDTO();
  }

  static async findById(id: string) {
    const task = await TaskModel.findById(id);
    return task ? task.toDTO() : null;
  }

  private static shuffleAssignees(assignees: string[]): string[] {
    for (let i = assignees.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [assignees[i], assignees[j]] = [assignees[j], assignees[i]];
    }
    return assignees;
  }
}

export interface CreateTaskDTO {
  groupId: string;
  title: string;
  description: string;
  assignees: string[];
  recurrence: {
    type: 'daily' | 'weekly' | 'custom';
    daysOfWeek?: number[];
    time: string;
  };
  status: 'active' | 'paused';
}

export interface TaskDTO {
  id: string;
  groupId: string;
  title: string;
  description: string;
  assignees: string[];
  rotationIndex: number;
  unavailableMembers?: string[];
  recurrence: {
    type: 'daily' | 'weekly' | 'custom';
    daysOfWeek?: number[];
    time: string;
  };
  status: 'active' | 'paused';
}

export interface UpdateAvailabilityDTO {
  id: string;
  unavailableMembers: string[];
}

import { z } from 'zod';

export const createTaskValidator = z.object({
  groupId: z.string(),
  title: z.string().min(1),
  description: z.string().min(1),
  assignees: z.array(z.string()),
  recurrence: z.object({
    type: z.enum(['daily', 'weekly', 'custom']),
    daysOfWeek: z.array(z.number()).optional(),
    time: z.string().regex(/^\d{2}:\d{2}$/),  // Matches "HH:MM" format
  }),
  status: z.enum(['active', 'paused'])
});

export const updateAvailabilityValidator = z.object({
  id: z.string(),
  unavailableMembers: z.array(z.string()),
});

export const rerollTaskValidator = z.object({
  id: z.string(),
});

import mongoose, { Schema } from 'mongoose';

const taskSchema = new Schema({
  groupId: { type: Schema.Types.ObjectId, required: true },
  title: { type: String, required: true },
  description: { type: String, required: true },
  assignees: [{ type: Schema.Types.ObjectId, required: true }],
  rotationIndex: { type: Number, required: true, default: 0 },
  unavailableMembers: [{ type: Schema.Types.ObjectId, default: [] }],
  recurrence: {
    type: { type: String, required: true },
    daysOfWeek: [{ type: Number, default: [] }],
    time: { type: String, required: true }
  },
  status: { type: String, required: true, enum: ['active', 'paused'] }
}, { timestamps: true });

// Convert MongoDB instance to DTO
taskSchema.methods.toDTO = function() {
  return {
    id: this._id.toString(),
    groupId: this.groupId.toString(),
    title: this.title,
    description: this.description,
    assignees: this.assignees.map((id: mongoose.ObjectId) => id.toString()),
    rotationIndex: this.rotationIndex,
    unavailableMembers: this.unavailableMembers.map((id: mongoose.ObjectId) => id.toString()),
    recurrence: this.recurrence,
    status: this.status
  };
};

export const TaskModel = mongoose.model('Task', taskSchema);
